import 'package:equatable/equatable.dart';

import 'after_prayer_azkar.dart';
import 'evening_azkar.dart';
import 'morning_azkar.dart';
import 'prophets_dua.dart';
import 'quran_dua.dart';
import 'sleep_azkar.dart';
import 'tasbeeh.dart';
import 'wakeup_azkar.dart';

class AzkarDataModel extends Equatable {
  final List<MorningAzkar>? morningAzkar;
  final List<EveningAzkar>? eveningAzkar;
  final List<AfterPrayerAzkar>? afterPrayerAzkar;
  final List<Tasbeeh>? tasbeeh;
  final List<SleepAzkar>? sleepAzkar;
  final List<WakeupAzkar>? wakeupAzkar;
  final List<QuranDua>? quranDuas;
  final List<ProphetsDua>? prophetsDuas;

  const AzkarDataModel({
    this.morningAzkar,
    this.eveningAzkar,
    this.afterPrayerAzkar,
    this.tasbeeh,
    this.sleepAzkar,
    this.wakeupAzkar,
    this.quranDuas,
    this.prophetsDuas,
  });

  factory AzkarDataModel.(
    Map<String, dynamic> json,
  ) {
    return AzkarDataModel(
      morningAzkar: (json['morning_azkar'] as List<dynamic>?)
          ?.map(
            (e) =>
                MorningAzkar.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      eveningAzkar: (json['evening_azkar'] as List<dynamic>?)
          ?.map(
            (e) =>
                EveningAzkar.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      afterPrayerAzkar: (json['after_prayer_azkar'] as List<dynamic>?)
          ?.map(
            (e) =>
                AfterPrayerAzkar.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      tasbeeh: (json['tasbeeh'] as List<dynamic>?)
          ?.map(
            (e) =>
                Tasbeeh.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      sleepAzkar: (json['sleep_azkar'] as List<dynamic>?)
          ?.map(
            (e) =>
                SleepAzkar.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      wakeupAzkar: (json['wakeup_azkar'] as List<dynamic>?)
          ?.map(
            (e) =>
                WakeupAzkar.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      quranDuas: (json['quran_duas'] as List<dynamic>?)
          ?.map(
            (e) =>
                QuranDua.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      prophetsDuas: (json['prophets_duas'] as List<dynamic>?)
          ?.map(
            (e) =>
                ProphetsDua.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
    );
  }

  Map<String, dynamic>
  () {
    return {
      'morning_azkar': morningAzkar
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'evening_azkar': eveningAzkar
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'after_prayer_azkar': afterPrayerAzkar
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'tasbeeh': tasbeeh
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'sleep_azkar': sleepAzkar
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'wakeup_azkar': wakeupAzkar
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'quran_duas': quranDuas
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'prophets_duas': prophetsDuas
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
    };
  }

  @override
  List<Object?> get props {
    return [
      morningAzkar,
      eveningAzkar,
      afterPrayerAzkar,
      tasbeeh,
      sleepAzkar,
      wakeupAzkar,
      quranDuas,
      prophetsDuas,
    ];
  }
}
